import React from 'react';
import {
  Card,
  Stack,
  Heading,
  Text,
  Divider,
  Box,
  Spacer
} from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ 
    day?: string; 
    icon?: string; 
    high?: number; 
    low?: number 
  }>;
}

/**
 * WeatherCard Component
 * Displays current weather information and a 5-day forecast.
 */
const WeatherCard: React.FC<Props> = ({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast
}) => {
  return (
    <>
      <style>{`
        .weather-card-root {
          transition: transform 200ms ease, box-shadow 200ms ease;
          background-color: var(--ggui-color-surfaceVariant, #f4f4f5) !important;
        }
        .weather-card-root:hover {
          transform: translateY(-4px);
        }
        .forecast-item {
          transition: transform 200ms ease, background-color 200ms ease;
          border-radius: var(--ggui-shape-radius-md, 8px);
          cursor: default;
        }
        .forecast-item:hover {
          transform: scale(1.05);
          background-color: var(--ggui-color-neutral-50, #f9fafb);
        }
      `}</style>

      <Card 
        shadow="md" 
        radius="xl" 
        border={true}
        padding={0} // We will use padding on the internal Stack for better control
      >
        <div className="weather-card-root" style={{ borderRadius: 'inherit', height: '100%' }}>
          <Stack gap={24} padding={24} role="region" aria-label={`Weather in ${city}`}>
            {/* Header: City and Unit */}
            <Stack direction="horizontal" justify="between" align="center">
              <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                {city}
              </Heading>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                °{unit}
              </Text>
            </Stack>

            {/* Main Weather Info */}
            <Stack align="center" gap={8}>
              <Text 
                size="4xl" 
                weight="bold" 
                color="var(--ggui-color-onSurface, #18181b)"
                aria-label={`Current temperature is ${temperature} degrees ${unit}`}
              >
                {temperature}°
              </Text>
              <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {condition}
              </Text>
            </Stack>

            {/* Metrics Row: Humidity and Wind */}
            <Box 
              padding={16} 
              background="var(--ggui-color-neutral-100, #f3f4f6)" 
              borderRadius="var(--ggui-shape-radius-lg, 12px)"
            >
              <Stack direction="horizontal" justify="around">
                <Stack align="center" gap={4}>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Humidity
                  </Text>
                  <Text variant="label" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                    {humidity}%
                  </Text>
                </Stack>
                <Divider orientation="vertical" margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />
                <Stack align="center" gap={4}>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Wind
                  </Text>
                  <Text variant="label" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                    {windSpeed} km/h
                  </Text>
                </Stack>
              </Stack>
            </Box>

            <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

            {/* 5-Day Forecast Strip */}
            <Stack direction="horizontal" justify="between" align="center" gap={8} wrap={false}>
              {forecast.map((item, index) => (
                <Box key={index} padding={8} className="forecast-item">
                  <Stack align="center" gap={4}>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {item.day}
                    </Text>
                    <Text size="lg" aria-hidden="true">
                      <span role="img">{item.icon}</span>
                    </Text>
                    <Stack direction="horizontal" gap={4} align="center">
                      <Text 
                        size="sm" 
                        weight="semibold" 
                        color="var(--ggui-color-primary-600, #0284c7)"
                      >
                        {item.high}°
                      </Text>
                      <Text 
                        size="sm" 
                        color="var(--ggui-color-neutral-500, #6b7280)"
                      >
                        {item.low}°
                      </Text>
                    </Stack>
                  </Stack>
                </Box>
              ))}
            </Stack>
          </Stack>
        </div>
      </Card>
    </>
  );
};

export default WeatherCard;
